class Solution:
    def hardestWorker(self, n, logs):
        durations = []
        prev = 0
        for cid, t in logs:
            durations.append((t - prev, cid))
            prev = t
        # pick max duration, smallest id on tie, via full sort
        durations.sort(key=lambda x: (-x[0], x[1]))
        return durations[0][1]

