class Solution:
    def hardestWorker(self, n, logs):
        prev = 0
        best_dur = -1
        best_id = -1
        for cid, t in logs:
            dur = t - prev
            prev = t
            if dur > best_dur or (dur == best_dur and cid < best_id):
                best_dur = dur
                best_id = cid
        return best_id

