var hardestWorker = function(n, logs) {
    let prev = 0;
    let bestDur = -1;
    let bestId = -1;
    for (const [cid, t] of logs) {
        const dur = t - prev;
        prev = t;
        if (dur > bestDur || (dur === bestDur && cid < bestId)) {
            bestDur = dur;
            bestId = cid;
        }
    }
    return bestId;
